"""Router for Token — generated by BackendAgent."""
from __future__ import annotations

from fastapi import APIRouter, HTTPException

from schemas import TokenCreate, TokenUpdate, TokenResponse
from services import TokenService

router = APIRouter()
_service = TokenService()


@router.get("/", response_model=list[TokenResponse])
def list_tokens() -> list:
    """List all tokens."""
    return _service.list_tokens()


@router.post("/", response_model=TokenResponse, status_code=201)
def create_token(data: TokenCreate) -> object:
    """Create a new token."""
    try:
        return _service.create_token(data.model_dump())
    except NotImplementedError:
        raise HTTPException(status_code=501, detail="Not yet implemented")


@router.get("/{id}", response_model=TokenResponse)
def get_token(id: str) -> object:
    """Get a single token by id."""
    item = _service.get_token(id)
    if item is None:
        raise HTTPException(status_code=404, detail="Token not found")
    return item


@router.put("/{id}", response_model=TokenResponse)
def update_token(id: str, data: TokenUpdate) -> object:
    """Update an existing token."""
    try:
        result = _service.update_token(id, data.model_dump(exclude_unset=True))
    except NotImplementedError:
        raise HTTPException(status_code=501, detail="Not yet implemented")
    if result is None:
        raise HTTPException(status_code=404, detail="Token not found")
    return result


@router.delete("/{id}", status_code=204)
def delete_token(id: str) -> None:
    """Delete a token. Level-3 action — requires permission check."""
    if not _service.delete_token(id):
        raise HTTPException(status_code=404, detail="Token not found")
